parameters.inputSchema:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "title": "LevelChapters",
  "type": "object",
  "properties": {
    "chapters": {
      "type": "array",
      "description": "The complete list of parsed levels/chapters extracted from the input text.",
      "items": {
        "type": "object",
        "properties": {
          "level": {
            "type": "integer",
            "description": "The sequential number of the level (e.g., 1, 2, 10)."
          },
          "title": {
            "type": "string",
            "description": "The name or title of the level."
          },
          "content": {
            "type": "string",
            "description": "The full narrative text belonging to this level, preserved exactly as written."
          }
        },
        "required": ["level", "title", "content"]
      }
    }
  },
  "required": ["chapters"]
}

{
  "name": "level_breakdown",
  "description": "Parses narrative text containing sequential 'Level N: Title' sections into a structured array, regardless of how many levels are present.",
  "schema": {
    "type": "object",
    "properties": {
      "levels": {
        "type": "array",
        "description": "An array of parsed level objects. Length is variable and depends on how many 'Level N:' headings are detected in the source text.",
        "items": {
          "type": "object",
          "properties": {
            "level_number": {
              "type": "integer",
              "description": "The numeric value extracted from the 'Level N:' heading."
            },
            "title": {
              "type": "string",
              "description": "The text following the colon on the heading line, trimmed of whitespace."
            },
            "content": {
              "type": "string",
              "description": "The full verbatim body text belonging to this level, excluding the heading line, with paragraph breaks preserved as double newlines."
            },
            "word_count": {
              "type": "integer",
              "description": "Approximate word count of the content field."
            }
          },
          "required": ["level_number", "title", "content", "word_count"],
          "additionalProperties": false
        }
      }
    },
    "required": ["levels"],
    "additionalProperties": false
  }
}
